import { Link } from 'react-router-dom'
import './Home.css'
import CreatePost from "../components/CreatePost";
import Feed from "../components/Feed";

const Home = () => {

    const scrollToPosts = () => {
        const section = document.getElementById("post-section");
        if (section) {
            section.scrollIntoView({ behavior: "smooth" });
        }
    };

    return (
        <div className="home">

            {/* Background Glow */}
            <div className="background-glow"></div>

            {/* Hero Section */}
            <section className="hero">
                <div className="hero-glow"></div>

                <div className="hero-content animate-slideUp">
                    <img 
                        src="/assets/logo-light.png" 
                        alt="Connect" 
                        className="hero-logo" 
                    />
                    <h1 className="hero-title">Connect</h1>
                    <p className="hero-tagline">Let's grow together</p>

                    <div className="hero-actions">

                        <Link to="/community" className="btn btn-secondary">
                            Explore Community
                        </Link>

                        {/* ✅ FIXED BUTTON */}
                        <button 
                            className="btn btn-primary"
                            onClick={scrollToPosts}
                        >
                            Get Started
                        </button>

                    </div>
                </div>
            </section>

            {/* Features Section */}
            <section className="features container section-cool-adaptive">
                <div className="features-grid">

                    <div className="feature-card">
                        <span className="feature-icon">💬</span>
                        <h3>Learn & Discuss</h3>
                        <p>Ask questions, share ideas, and learn from real experiences.</p>
                    </div>

                    <div className="feature-card">
                        <span className="feature-icon">🤝</span>
                        <h3>Collaborate</h3>
                        <p>Work with like-minded people to build and improve products.</p>
                    </div>

                    <div className="feature-card">
                        <span className="feature-icon">🚀</span>
                        <h3>Grow Projects</h3>
                        <p>Showcase your ideas, get feedback, and evolve faster.</p>
                    </div>

                </div>
            </section>

            {/* ================= NEW FUNCTIONAL SECTION ================= */}

            {/* Create Post */}
            <div id="post-section" style={{ marginTop: "40px", padding: "20px" }}>
                <CreatePost />
            </div>

            {/* Feed */}
            <div style={{ marginTop: "20px", padding: "20px" }}>
                <Feed />
            </div>

        </div>
    )
}

export default Home;
